BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?type ?name WHERE {
  VALUES ?elem {
    <http://api.koneksys.com/cameo/TMT/block/Modeling%20Support::Roll-up%20Pattern::ErrorRollUpPatternElement>
    <http://api.koneksys.com/cameo/TMT/block/Modeling%20Support::Roll-up%20Pattern::PowerRollUpPattern>
    <http://api.koneksys.com/cameo/TMT/block/Modeling%20Support::Roll-up%20Pattern::RootSumSquaredRollUp>
    <http://api.koneksys.com/cameo/TMT/constraint%20block/Modeling%20Support::Roll-up%20Pattern::RootSumSquared>
  }
  ?elem vocab:NamedElement_name ?name .
  ?elem rdf:type ?type .
}

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?type WHERE {
  VALUES ?elem {
    <http://api.koneksys.com/cameo/TMT/block/Modeling%20Support::Roll-up%20Pattern::ErrorRollUpPatternElement>
  }
  ?elem vocab:Element_ownedElement ?child .
  ?child vocab:NamedElement_name ?name .
  ?child rdf:type ?type .
}
LIMIT 30
